INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_A1_01','run','/rʌn/','verb','달리다','To move quickly on foot.','I {run} every morning in the park.','저는 매일 아침 공원에서 달려요.','run','A1','sports',1,'running person park morning exercise'),
('w_sports_A1_02','play','/pleɪ/','verb','(스포츠를) 하다','To take part in a sport or game.','Do you {play} football on weekends?','주말에 축구 하세요?','play','A1','sports',1,'kids playing football field fun'),
('w_sports_A1_03','win','/wɪn/','verb','이기다','To finish first or be the best in a competition.','Our team wants to {win} the match.','우리 팀은 경기에서 이기고 싶어요.','win','A1','sports',1,'winning team trophy celebration cheering'),
('w_sports_A1_04','lose','/luːz/','verb','지다','To not win a game or competition.','It''s okay to {lose} sometimes — you learn from it.','가끔 지는 건 괜찮아요. 거기서 배우니까요.','lose','A1','sports',2,'sad athlete losing game disappointment'),
('w_sports_A1_05','team','/tiːm/','noun','팀','A group of people who play or work together.','I joined a basketball {team} last month.','지난달에 농구 팀에 들어갔어요.','team','A1','sports',1,'sports team group together jerseys'),
('w_sports_A1_06','ball','/bɔːl/','noun','공','A round object used in many sports.','Kick the {ball} into the goal.','공을 골대 안으로 차세요.','ball','A1','sports',1,'soccer ball football grass sport'),
('w_sports_A1_07','game','/ɡeɪm/','noun','경기, 게임','An activity with rules in which people compete.','The {game} starts at seven tonight.','경기는 오늘 밤 7시에 시작돼요.','game','A1','sports',1,'sports game stadium crowd night'),
('w_sports_A1_08','swim','/swɪm/','verb','수영하다','To move through water using the body.','She can {swim} very fast.','그녀는 수영을 아주 빠르게 할 수 있어요.','swim','A1','sports',1,'swimmer pool water lane splash'),
('w_sports_A1_09','jump','/dʒʌmp/','verb','점프하다','To push yourself off the ground into the air.','He can {jump} over one meter high.','그는 1미터 이상 높이 뛸 수 있어요.','jump','A1','sports',1,'athlete jumping high jump track field'),
('w_sports_A1_10','fast','/fæst/','adjective','빠른','Moving or able to move at high speed.','The runner is very {fast}.','그 달리기 선수는 정말 빠르네요.','fast','A1','sports',2,'sprinter running track fast speed motion'),
('w_sports_A1_11','sport','/spɔːrt/','noun','스포츠, 운동','An activity involving physical effort and skill, often competitive.','What is your favourite {sport}?','제일 좋아하는 스포츠가 뭐예요?','sport','A1','sports',1,'various sports equipment collage'),
('w_sports_A1_12','kick','/kɪk/','verb','차다','To hit something with your foot.','{Kick} the ball toward the goal.','공을 골대 쪽으로 차세요.','Kick','A1','sports',2,'football player kicking ball action'),
('w_sports_A1_13','throw','/θroʊ/','verb','던지다','To send something through the air by moving your arm.','Can you {throw} me the ball?','공 좀 던져줄 수 있어요?','throw','A1','sports',2,'athlete throwing ball action sport'),
('w_sports_A1_14','catch','/kætʃ/','verb','잡다','To take hold of something moving through the air.','Try to {catch} the ball with both hands.','두 손으로 공을 잡아보세요.','catch','A1','sports',2,'player catching ball baseball glove'),
('w_sports_A1_15','hit','/hɪt/','verb','치다, 때리다','To strike something with force.','She {hit} the ball over the net.','그녀가 공을 네트 너머로 쳤어요.','hit','A1','sports',2,'tennis player hitting ball racket'),
('w_sports_A1_16','goal','/ɡoʊl/','noun','골, 목표','A point scored in football or hockey, or the target itself.','He scored a {goal} in the last minute.','그는 마지막 1분에 골을 넣었어요.','goal','A1','sports',1,'soccer goal net ball scored'),
('w_sports_A1_17','race','/reɪs/','noun','경주','A competition to see who is the fastest.','I want to run in a 5km {race} next month.','다음 달에 5킬로미터 달리기 경주에 나가고 싶어요.','race','A1','sports',1,'runners race track competition start line'),
('w_sports_A1_18','walk','/wɔːk/','verb','걷다','To move at a regular pace by lifting and setting down each foot.','Let''s {walk} to the stadium together.','같이 걸어서 경기장에 가요.','walk','A1','sports',3,'people walking park morning exercise'),
('w_sports_A1_19','strong','/strɔːŋ/','adjective','강한','Having great physical power.','Athletes need to be {strong} and flexible.','운동선수는 강하고 유연해야 해요.','strong','A1','sports',2,'strong athlete muscles workout gym'),
('w_sports_A1_20','tired','/taɪərd/','adjective','피곤한','Feeling like you need to rest or sleep.','I feel {tired} after the long practice.','긴 연습 후에 피곤해요.','tired','A1','sports',2,'tired athlete resting bench sweat'),
('w_sports_A1_21','water','/ˈwɔːtər/','noun','물','A liquid that people drink, especially important during exercise.','Drink plenty of {water} during exercise.','운동 중에는 물을 충분히 마세요.','water','A1','sports',2,'athlete drinking water bottle sports'),
('w_sports_A1_22','tennis','/ˈtenɪs/','noun','테니스','A sport played with rackets on a court.','I play {tennis} every Saturday morning.','저는 매주 토요일 아침에 테니스를 쳐요.','tennis','A1','sports',2,'tennis court player racket ball'),
('w_sports_A1_23','football','/ˈfʊtbɔːl/','noun','축구 (= 미식 축구)','A sport played with a ball between two teams.','He watched a {football} match on TV.','그는 TV로 축구 경기를 봤어요.','football','A1','sports',2,'football game stadium crowd green field'),
('w_sports_A1_24','gym','/dʒɪm/','noun','체육관','A room or building with equipment for physical exercise.','I go to the {gym} three times a week.','일주일에 세 번 헬스장에 가요.','gym','A1','sports',1,'gym workout equipment weights fitness'),
('w_sports_A1_25','score','/skɔːr/','noun','점수','The number of points made in a game or competition.','What is the {score}?','지금 점수가 어떻게 돼요?','score','A1','sports',1,'scoreboard sports stadium numbers game'),
('w_sports_A1_26','easy','/ˈiːzi/','adjective','쉬운','Not difficult.','This exercise is not {easy} for beginners.','이 운동은 초보자에게 쉽지 않아요.','easy','A1','sports',3,'beginner exercise simple movement'),
('w_sports_A1_27','hard','/hɑːrd/','adjective','힘든, 어려운','Requiring a great deal of endurance or effort.','Training every day is really {hard}.','매일 훈련하는 것은 정말 힘들어요.','hard','A1','sports',2,'athlete training hard workout intense'),
('w_sports_A1_28','start','/stɑːrt/','verb','시작하다','To begin doing something.','The race will {start} in five minutes.','경주는 5분 후에 시작돼요.','start','A1','sports',2,'race start line gun whistle athletes ready'),
('w_sports_A1_29','stop','/stɒp/','verb','멈추다','To cease doing something or moving.','The referee told everyone to {stop}.','심판이 모두에게 멈추라고 했어요.','stop','A1','sports',3,'referee whistle stop game players'),
('w_sports_A1_30','outside','/ˌaʊtˈsaɪd/','adverb','야외에서','In the open air.','Playing {outside} is good for your health.','야외에서 운동하면 건강에 좋아요.','outside','A1','sports',3,'outdoor sport kids playing field sun'),
('w_sports_A1_31','friend','/frend/','noun','친구','A person you know and like.','I play basketball with my {friend}s.','친구들과 농구를 해요.','friend','A1','sports',3,'friends playing sport together laughing'),
('w_sports_A1_32','bike','/baɪk/','noun','자전거','A two-wheeled vehicle you ride by pedalling.','I ride my {bike} to the park every weekend.','저는 매주 주말마다 자전거를 타고 공원에 가요.','bike','A1','sports',2,'cyclist riding bike park path outdoor'),
('w_sports_A1_33','move','/muːv/','verb','움직이다','To change position; to be physically active.','{Move} your body every day to stay healthy.','건강을 유지하려면 매일 몸을 움직이세요.','Move','A1','sports',2,'person stretching moving body exercise'),
('w_sports_A1_34','practice','/ˈpræktɪs/','noun','연습','Repeated exercise to improve skill.','We have {practice} every Tuesday evening.','매주 화요일 저녁에 연습이 있어요.','practice','A1','sports',1,'team practice training field players coach'),
('w_sports_A1_35','cool','/kuːl/','adjective','멋진, 훌륭한','Impressively good; also used for temperature.','That was a really {cool} move!','그것은 정말 멋진 동작이었어요!','cool','A1','sports',3,'impressive sports move dunk skateboard');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_A2_01','match','/mætʃ/','noun','경기','A game or contest between two teams or players.','Did you watch the football {match} last night?','어제 밤 축구 경기 봤어요?','match','A2','sports',1,'football match stadium crowd evening lights'),
('w_sports_A2_02','score','/skɔːr/','verb','득점하다','To gain a point or goal in a game.','She {scored} twice in the second half.','그녀는 후반전에 두 번 득점했어요.','scored','A2','sports',1,'athlete scoring goal celebration team'),
('w_sports_A2_03','practice','/ˈpræktɪs/','verb','연습하다','To do an activity repeatedly to improve.','You need to {practice} every day if you want to improve.','실력을 키우려면 매일 연습해야 해요.','practice','A2','sports',1,'athlete practicing skill repetition field'),
('w_sports_A2_04','athlete','/ˈæθliːt/','noun','운동선수','A person who is skilled in sports or physical exercise.','She is a professional {athlete} who runs marathons.','그녀는 마라톤을 뛰는 프로 운동선수예요.','athlete','A2','sports',1,'professional athlete training track stadium'),
('w_sports_A2_05','stadium','/ˈsteɪdiəm/','noun','경기장','A large structure with a field where sports are played.','The {stadium} was full of excited fans.','경기장은 흥분한 팬들로 가득 찼어요.','stadium','A2','sports',1,'large stadium full crowd sports event'),
('w_sports_A2_06','coach','/koʊtʃ/','noun','코치, 감독','A person who trains and instructs a team or player.','Our {coach} told us to stay focused.','코치님이 집중하라고 하셨어요.','coach','A2','sports',1,'sports coach giving instructions team players'),
('w_sports_A2_07','train','/treɪn/','verb','훈련하다','To practise or exercise for a sport.','He {trains} for two hours every day.','그는 매일 두 시간씩 훈련해요.','trains','A2','sports',1,'athlete training workout gym sweat'),
('w_sports_A2_08','compete','/kəmˈpiːt/','verb','경쟁하다','To take part in a competition or contest.','She will {compete} in the national championships.','그녀는 전국 대회에 참가할 거예요.','compete','A2','sports',1,'athletes competing race track field'),
('w_sports_A2_09','trophy','/ˈtroʊfi/','noun','트로피','A prize given to the winner of a competition.','The team held up the {trophy} after winning.','팀이 우승 후 트로피를 높이 들었어요.','trophy','A2','sports',1,'sports trophy golden cup winners celebration'),
('w_sports_A2_10','champion','/ˈtʃæmpiən/','noun','챔피언, 우승자','The winner of a competition or title.','She became the national swimming {champion}.','그녀는 전국 수영 챔피언이 됐어요.','champion','A2','sports',1,'champion athlete gold medal podium victory'),
('w_sports_A2_11','support','/səˈpɔːrt/','verb','응원하다','To give encouragement or help to someone.','All the fans came to {support} their team.','팬들이 모두 팀을 응원하러 왔어요.','support','A2','sports',2,'fans cheering supporting team stadium'),
('w_sports_A2_12','captain','/ˈkæptɪn/','noun','주장','The leader of a sports team.','She was chosen as the team {captain}.','그녀가 팀 주장으로 선발됐어요.','captain','A2','sports',1,'team captain armband leading players'),
('w_sports_A2_13','league','/liːɡ/','noun','리그','A group of sports teams that compete with each other.','Their team was promoted to a higher {league}.','그 팀이 더 높은 리그로 승격됐어요.','league','A2','sports',1,'football league table standings clubs'),
('w_sports_A2_14','final','/ˈfaɪnəl/','noun','결승전','The last and most important game in a competition.','We made it to the {final}!','우리가 결승에 올라갔어요!','final','A2','sports',1,'sports final match big stadium broadcast'),
('w_sports_A2_15','season','/ˈsiːzən/','noun','시즌','The period during which a sport is played.','The football {season} starts in August.','축구 시즌은 8월에 시작돼요.','season','A2','sports',2,'sports season calendar schedule fixtures'),
('w_sports_A2_16','fan','/fæn/','noun','팬, 응원자','A person who admires a sport, team, or athlete.','He is a huge {fan} of basketball.','그는 농구를 정말 좋아하는 팬이에요.','fan','A2','sports',2,'sports fan wearing jersey cheering stadium'),
('w_sports_A2_17','injury','/ˈɪndʒəri/','noun','부상','Harm done to the body, especially in sport.','He missed the match because of an {injury}.','그는 부상 때문에 경기를 뛰지 못했어요.','injury','A2','sports',1,'athlete injured knee treatment sports'),
('w_sports_A2_18','improve','/ɪmˈpruːv/','verb','향상되다','To get better at something.','You will {improve} if you practise regularly.','규칙적으로 연습하면 실력이 늘어요.','improve','A2','sports',1,'athlete improving skill training progress chart'),
('w_sports_A2_19','record','/ˈrekərd/','noun','기록','The best performance in a sport.','She broke the world {record} for the 100m sprint.','그녀가 100미터 단거리 세계 기록을 깼어요.','record','A2','sports',1,'world record sports achievement stopwatch'),
('w_sports_A2_20','fitness','/ˈfɪtnəs/','noun','체력, 건강 상태','The condition of being physically healthy and strong.','Regular exercise improves your {fitness} level.','규칙적인 운동이 체력을 향상시켜요.','fitness','A2','sports',1,'fitness gym workout health active'),
('w_sports_A2_21','round','/raʊnd/','noun','라운드, 회전','One stage of a competition.','They won in the first {round}.','그들은 1라운드에서 이겼어요.','round','A2','sports',2,'boxing round match ring bell'),
('w_sports_A2_22','draw','/drɔː/','noun','무승부','A result in which neither team wins.','The match ended in a {draw}.','경기가 무승부로 끝났어요.','draw','A2','sports',2,'sports draw tie equal score board'),
('w_sports_A2_23','warm up','/wɔːrm ʌp/','phrase','준비 운동을 하다','To do gentle exercise before a sport.','Always {warm up} before you start running.','달리기를 시작하기 전에 항상 준비 운동을 하세요.','warm up','A2','sports',1,'athlete warming up stretching before run'),
('w_sports_A2_24','defeat','/dɪˈfiːt/','verb','물리치다','To beat someone in a competition.','We {defeated} the opposing team 3–0.','우리가 상대팀을 3대 0으로 물리쳤어요.','defeated','A2','sports',2,'winning team defeating opponent celebrate'),
('w_sports_A2_25','foul','/faʊl/','noun','파울, 반칙','An action in sport that breaks the rules.','The referee gave a {foul} against the striker.','심판이 스트라이커에게 파울을 선언했어요.','foul','A2','sports',2,'referee calling foul football yellow card'),
('w_sports_A2_26','retire','/rɪˈtaɪər/','verb','은퇴하다','To stop playing a sport professionally.','The famous tennis player decided to {retire}.','그 유명한 테니스 선수가 은퇴하기로 결정했어요.','retire','A2','sports',2,'athlete retirement farewell speech press conference'),
('w_sports_A2_27','spectator','/spekˈteɪtər/','noun','관중, 관람객','A person who watches a sport or event.','Thousands of {spectators} filled the stands.','수천 명의 관중이 스탠드를 가득 채웠어요.','spectators','A2','sports',2,'spectators watching sports stadium crowd cheering'),
('w_sports_A2_28','award','/əˈwɔːrd/','noun','상, 어워드','A prize given for achievement.','She received the best player {award} of the season.','그녀는 시즌 최우수 선수상을 받았어요.','award','A2','sports',2,'sports award ceremony trophy podium'),
('w_sports_A2_29','pool','/puːl/','noun','수영장','An indoor or outdoor area filled with water for swimming.','She trains in the {pool} every morning.','그녀는 매일 아침 수영장에서 훈련해요.','pool','A2','sports',1,'swimming pool lanes indoor athletic training'),
('w_sports_A2_30','court','/kɔːrt/','noun','코트 (테니스·농구 등)','A marked area where a sport such as tennis is played.','The basketball {court} was newly renovated.','농구 코트가 새로 단장됐어요.','court','A2','sports',2,'basketball court indoor arena hardwood'),
('w_sports_A2_31','pitch','/pɪtʃ/','noun','경기장 잔디 (축구 등)','A grassy area on which football or cricket is played.','The players ran onto the {pitch}.','선수들이 경기장으로 뛰어나왔어요.','pitch','A2','sports',2,'football pitch grass green lines stadium'),
('w_sports_A2_32','cheer','/tʃɪər/','verb','응원하다','To shout encouragement to support a team.','The crowd began to {cheer} loudly.','군중이 크게 응원하기 시작했어요.','cheer','A2','sports',2,'crowd cheering stadium noise celebration'),
('w_sports_A2_33','result','/rɪˈzʌlt/','noun','결과','The score or outcome of a game or competition.','What was the {result} of last night''s game?','어젯밤 경기 결과가 어떻게 됐어요?','result','A2','sports',1,'sports result scoreboard final standings'),
('w_sports_A2_34','sprint','/sprɪnt/','verb','전력 질주하다','To run very fast for a short distance.','She {sprinted} to the finish line.','그녀가 결승선까지 전력 질주했어요.','sprinted','A2','sports',2,'sprinter finish line fast track athlete'),
('w_sports_A2_35','medal','/ˈmedəl/','noun','메달','A metal disc awarded to winners of a competition.','She won a gold {medal} at the Olympics.','그녀는 올림픽에서 금메달을 땄어요.','medal','A2','sports',1,'gold medal olympics podium winner sport');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_B1_01','tournament','/ˈtʊrnəmənt/','noun','토너먼트, 대회','A series of contests between teams or players.','We entered a national {tournament} last summer.','지난여름에 전국 토너먼트에 참가했어요.','tournament','B1','sports',1,'sports tournament bracket competition teams'),
('w_sports_B1_02','strategy','/ˈstrætədʒi/','noun','전략','A plan designed to achieve a goal.','The coach explained the team''s {strategy} for the final.','코치가 결승전을 위한 팀 전략을 설명했어요.','strategy','B1','sports',1,'sports strategy whiteboard tactics coach'),
('w_sports_B1_03','injury','/ˈɪndʒəri/','noun','부상 (심화)','Significant physical damage to the body stopping play.','He is recovering from a serious knee {injury}.','그는 심각한 무릎 부상에서 회복 중이에요.','injury','B1','sports',1,'sports injury knee treatment physiotherapy'),
('w_sports_B1_04','sportsmanship','/ˈspɔːrtsmənʃɪp/','noun','스포츠맨십','Fair and generous behaviour in sport.','Winning is important, but {sportsmanship} matters more.','이기는 것도 중요하지만, 스포츠맨십이 더 중요해요.','sportsmanship','B1','sports',2,'athletes shaking hands respect fair play'),
('w_sports_B1_05','referee','/ˌrefəˈriː/','noun','심판','An official who ensures rules are followed in a sport.','The {referee} blew the whistle for full time.','심판이 종료 휘슬을 불었어요.','referee','B1','sports',1,'referee whistle yellow card football game'),
('w_sports_B1_06','penalty','/ˈpenəlti/','noun','패널티, 벌칙','A punishment for breaking a rule in sport.','The team was awarded a {penalty} kick.','그 팀에게 패널티 킥이 주어졌어요.','penalty','B1','sports',1,'penalty kick football goalkeeper spot'),
('w_sports_B1_07','sponsor','/ˈspɒnsər/','noun','후원자, 스폰서','A company or person who gives money to support sport.','The event''s main {sponsor} is a sports drink brand.','대회의 주요 스폰서는 스포츠 음료 브랜드예요.','sponsor','B1','sports',2,'sports sponsor logo jersey event banner'),
('w_sports_B1_08','league','/liːɡ/','noun','프로 리그','An organised competition among several teams.','He plays in the top professional {league}.','그는 최상위 프로 리그에서 뛰어요.','league','B1','sports',1,'professional football league table clubs'),
('w_sports_B1_09','championship','/ˈtʃæmpiənʃɪp/','noun','선수권 대회','A competition to find the best team or player.','She won the world {championship} three times.','그녀는 세계 선수권 대회에서 세 번 우승했어요.','championship','B1','sports',1,'world championship trophy ceremony stadium'),
('w_sports_B1_10','endurance','/ɪnˈdjʊərəns/','noun','지구력','The ability to maintain effort for a long time.','Marathon runners need excellent {endurance}.','마라톤 선수는 뛰어난 지구력이 필요해요.','endurance','B1','sports',1,'marathon runner long distance endurance'),
('w_sports_B1_11','formation','/fɔːrˈmeɪʃən/','noun','포메이션, 대형','The way players are positioned on a field.','The coach changed the team''s {formation} at halftime.','코치가 하프타임에 팀의 포메이션을 바꿨어요.','formation','B1','sports',2,'football formation tactics board'),
('w_sports_B1_12','substitute','/ˈsʌbstɪtjuːt/','noun','교체 선수','A player who enters the game to replace another.','The coach made a {substitute} in the 70th minute.','코치가 70분에 선수 교체를 했어요.','substitute','B1','sports',2,'player substitution warm up sideline bench'),
('w_sports_B1_13','transfer','/ˈtrænsfɜːr/','noun','이적','Moving from one sports team to another.','His {transfer} to a European club was big news.','그의 유럽 클럽 이적은 큰 뉴스였어요.','transfer','B1','sports',2,'football player transfer signing new jersey'),
('w_sports_B1_14','qualification','/ˌkwɒlɪfɪˈkeɪʃən/','noun','예선 통과, 자격 획득','The process of reaching a required standard to enter.','The team secured {qualification} for the World Cup.','그 팀이 월드컵 본선 진출권을 확보했어요.','qualification','B1','sports',2,'team celebrating qualification world cup'),
('w_sports_B1_15','stamina','/ˈstæmɪnə/','noun','지구력, 스태미나','Physical or mental endurance over a long period.','Building {stamina} requires consistent training.','스태미나를 키우려면 꾸준한 훈련이 필요해요.','stamina','B1','sports',1,'runner endurance long distance stamina training'),
('w_sports_B1_16','momentum','/məˈmentəm/','noun','기세, 모멘텀','A driving force that makes something continue.','The team gained {momentum} after the first goal.','첫 골을 넣은 후 팀의 기세가 올라갔어요.','momentum','B1','sports',2,'sports momentum team energy crowd excitement'),
('w_sports_B1_17','offside','/ˌɒfˈsaɪd/','adjective','오프사이드의','In a position not allowed by the rules of a sport.','The goal was disallowed for {offside}.','그 골은 오프사이드로 취소됐어요.','offside','B1','sports',2,'football offside flag referee rule'),
('w_sports_B1_18','dribble','/ˈdrɪbəl/','verb','드리블하다','To move a ball forward using repeated small kicks or bounces.','He {dribbled} past three defenders before scoring.','그는 세 명의 수비수를 제치고 드리블한 후 득점했어요.','dribbled','B1','sports',2,'football player dribbling past defenders'),
('w_sports_B1_19','overtime','/ˈoʊvərtaɪm/','noun','연장전','Extra time added to the end of a match.','The game went to {overtime} after a 1–1 draw.','경기가 1대 1 무승부 후 연장전에 돌입했어요.','overtime','B1','sports',2,'overtime football match extra time clock'),
('w_sports_B1_20','comeback','/ˈkʌmbæk/','noun','역전, 복귀','A recovery in sport after being behind.','The team made an incredible {comeback} in the second half.','팀이 후반전에 믿을 수 없는 역전을 이뤄냈어요.','comeback','B1','sports',1,'sports comeback celebration victory underdog'),
('w_sports_B1_21','underdog','/ˈʌndərdɒɡ/','noun','약팀, 불리한 쪽','A competitor expected to lose.','Everyone was surprised when the {underdog} won.','약팀이 이기자 모두가 놀랐어요.','underdog','B1','sports',2,'underdog winning upset celebration surprise'),
('w_sports_B1_22','motivate','/ˈmoʊtɪveɪt/','verb','동기를 부여하다','To give someone a reason or desire to do something.','The coach knows how to {motivate} the players.','코치는 선수들에게 동기를 부여하는 방법을 알아요.','motivate','B1','sports',2,'coach motivating players team talk locker room'),
('w_sports_B1_23','discipline','/ˈdɪsɪplɪn/','noun','규율, 자기 관리','Training that produces self-control and skill.','Athletic success requires great {discipline}.','운동 성공에는 대단한 자기 관리가 필요해요.','discipline','B1','sports',1,'athlete disciplined training routine focused'),
('w_sports_B1_24','setback','/ˈsetbæk/','noun','역경, 좌절','A problem that stops progress or makes things worse.','Every athlete faces {setback}s on the road to success.','모든 선수는 성공의 길에서 역경을 겪어요.','setback','B1','sports',2,'athlete sitting head down setback recovery'),
('w_sports_B1_25','versatile','/ˈvɜːrsətaɪl/','adjective','다재다능한','Able to perform many different sports or roles.','A {versatile} player can fill several positions.','다재다능한 선수는 여러 포지션을 소화할 수 있어요.','versatile','B1','sports',2,'player multiple positions versatile sport'),
('w_sports_B1_26','eliminate','/ɪˈlɪmɪneɪt/','verb','탈락시키다','To remove a team or player from a competition.','They were {eliminated} in the quarter-finals.','그들은 8강에서 탈락했어요.','eliminated','B1','sports',2,'sports elimination knockout bracket stage'),
('w_sports_B1_27','recover','/rɪˈkʌvər/','verb','회복하다','To return to a normal state of health after injury.','It took six months for him to {recover} fully.','그가 완전히 회복하는 데 6개월이 걸렸어요.','recover','B1','sports',1,'athlete recovery physiotherapy rehab sports'),
('w_sports_B1_28','squad','/skwɒd/','noun','스쿼드, 선발 명단','The full group of players from which a team is selected.','The coach announced the {squad} for the tournament.','코치가 토너먼트 스쿼드를 발표했어요.','squad','B1','sports',2,'football squad team photo lineup uniform'),
('w_sports_B1_29','possession','/pəˈzeʃən/','noun','볼 점유율','In sport, having control of the ball.','The team kept {possession} for most of the game.','그 팀이 경기 대부분 동안 볼 점유율을 유지했어요.','possession','B1','sports',2,'football possession stats ball control team'),
('w_sports_B1_30','rivalry','/ˈraɪvəlri/','noun','라이벌 관계','A strong competitive relationship between two teams.','The {rivalry} between those two clubs is legendary.','두 클럽 사이의 라이벌 관계는 전설적이에요.','rivalry','B1','sports',1,'sports rival teams classic match derby'),
('w_sports_B1_31','streak','/striːk/','noun','연승, 연속 기록','A series of wins or losses without a break.','The team is on a ten-game winning {streak}.','팀이 10경기 연승 행진 중이에요.','streak','B1','sports',2,'winning streak sports calendar consecutive wins'),
('w_sports_B1_32','outperform','/ˌaʊtpəˈfɔːrm/','verb','더 뛰어난 성과를 내다','To do better than another person or team.','She consistently {outperforms} her rivals.','그녀는 꾸준히 라이벌들보다 뛰어난 성과를 내요.','outperforms','B1','sports',2,'athlete outperforming rival race podium'),
('w_sports_B1_33','qualify','/ˈkwɒlɪfaɪ/','verb','예선을 통과하다','To reach a required standard to enter a competition.','She {qualified} for the Olympic trials.','그녀가 올림픽 선발전 예선을 통과했어요.','qualified','B1','sports',1,'athlete qualifying race finish celebration'),
('w_sports_B1_34','halftime','/ˈhɑːftaɪm/','noun','하프타임','The break in the middle of a game.','At {halftime}, the score was 2–0.','하프타임에 점수는 2대 0이었어요.','halftime','B1','sports',2,'football halftime break tunnel locker room'),
('w_sports_B1_35','spectacle','/ˈspektəkəl/','noun','장관, 볼거리','An impressive display or event.','The opening ceremony was a stunning {spectacle}.','개막식은 놀라운 장관이었어요.','spectacle','B1','sports',2,'sports opening ceremony fireworks stadium spectacular');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_B2_01','analytics','/ˌænəˈlɪtɪks/','noun','스포츠 분석','Statistical analysis used to measure performance.','Teams use {analytics} to plan their tactics.','팀들은 전술을 계획하기 위해 분석을 활용해요.','analytics','B2','sports',1,'sports analytics data dashboard screen laptop'),
('w_sports_B2_02','biomechanics','/ˌbaɪoʊmɪˈkænɪks/','noun','생체역학','The study of how forces affect the human body in motion.','Sprinters work with {biomechanics} experts to refine technique.','단거리 선수들은 기술을 다듬기 위해 생체역학 전문가와 함께 일해요.','biomechanics','B2','sports',1,'athlete motion capture lab biomechanics analysis'),
('w_sports_B2_03','doping','/ˈdoʊpɪŋ/','noun','도핑','Using prohibited substances to enhance athletic performance.','The athlete was suspended for {doping}.','그 선수는 도핑으로 인해 출전 정지됐어요.','doping','B2','sports',1,'anti-doping test sports ethics lab sample'),
('w_sports_B2_04','physiotherapy','/ˌfɪziəʊˈθerəpi/','noun','물리치료','Treatment of injury using physical methods.','She underwent months of {physiotherapy} after the surgery.','그녀는 수술 후 수개월간 물리치료를 받았어요.','physiotherapy','B2','sports',1,'physiotherapy sports injury treatment rehab table'),
('w_sports_B2_05','periodization','/ˌpɪəriədaɪˈzeɪʃən/','noun','주기화 훈련','Dividing a training programme into planned phases.','Elite athletes use {periodization} to peak at competitions.','엘리트 선수들은 대회에서 최고 컨디션을 내기 위해 주기화 훈련을 사용해요.','periodization','B2','sports',1,'training periodization plan calendar phases chart'),
('w_sports_B2_06','agility','/əˈdʒɪlɪti/','noun','민첩성','The ability to move quickly and easily.','Agility drills improve a player''s {agility} on the field.','민첩성 훈련은 경기장에서 선수의 민첩성을 향상시켜요.','agility','B2','sports',1,'agility ladder drill athlete fast feet training'),
('w_sports_B2_07','stamina','/ˈstæmɪnə/','noun','지속적 체력 (상세)','Sustained physical and mental endurance over time.','Building {stamina} is essential for endurance events.','지속적 체력을 기르는 것은 지구력 종목에 필수예요.','stamina','B2','sports',1,'marathon runner endurance race long distance'),
('w_sports_B2_08','sprint','/sprɪnt/','noun','단거리 질주, 스프린트','A short burst of maximum speed.','She finished the race with a powerful final {sprint}.','그녀는 강력한 막판 스프린트로 경주를 마쳤어요.','sprint','B2','sports',1,'sprinter 100m track starting blocks explosive'),
('w_sports_B2_09','tactical','/ˈtæktɪkəl/','adjective','전술적인','Relating to a plan to achieve a goal in sport.','The manager made a {tactical} substitution late in the game.','감독이 경기 후반에 전술적인 교체를 했어요.','tactical','B2','sports',1,'football tactics board coach planning strategy'),
('w_sports_B2_10','performance','/pərˈfɔːrməns/','noun','경기력, 퍼포먼스','How well an athlete or team performs.','Her {performance} in the finals was outstanding.','결승전에서 그녀의 경기력은 탁월했어요.','performance','B2','sports',1,'athlete peak performance sports competition'),
('w_sports_B2_11','concussion','/kənˈkʌʃən/','noun','뇌진탕','A head injury causing temporary loss of function.','He was taken off after suffering a {concussion}.','그는 뇌진탕 증상을 보인 후 경기에서 제외됐어요.','concussion','B2','sports',1,'sports concussion head injury medical team'),
('w_sports_B2_12','hydration','/haɪˈdreɪʃən/','noun','수분 보충','The process of absorbing adequate water into the body.','Proper {hydration} is key to athletic performance.','충분한 수분 보충은 운동 능력의 핵심이에요.','hydration','B2','sports',1,'athlete drinking sports drink hydration water'),
('w_sports_B2_13','recovery','/rɪˈkʌvəri/','noun','회복 (훈련)','The process of returning to peak condition after exertion.','Ice baths are popular for post-training {recovery}.','얼음 목욕은 훈련 후 회복에 많이 사용돼요.','recovery','B2','sports',1,'athlete ice bath recovery sports muscle'),
('w_sports_B2_14','explosive','/ɪkˈsploʊsɪv/','adjective','폭발적인','Involving a rapid release of energy in a short time.','Sprinters need {explosive} power off the starting blocks.','단거리 선수는 출발 블록에서 폭발적인 힘이 필요해요.','explosive','B2','sports',1,'sprinter starting blocks explosive power track'),
('w_sports_B2_15','conditioning','/kənˈdɪʃənɪŋ/','noun','컨디셔닝, 체력 단련','A programme of exercises to improve fitness.','Off-season {conditioning} keeps athletes in shape.','비시즌 컨디셔닝이 선수들의 체형을 유지시켜요.','conditioning','B2','sports',1,'athlete conditioning training gym off season'),
('w_sports_B2_16','fatigue','/fəˈtiːɡ/','noun','피로','Extreme tiredness resulting from exertion.','Muscle {fatigue} set in during the final kilometre.','마지막 1킬로미터에서 근육 피로가 왔어요.','fatigue','B2','sports',1,'athlete exhausted fatigue end of race tired'),
('w_sports_B2_17','resilience','/rɪˈzɪliəns/','noun','회복 탄력성','The ability to recover quickly from difficulty.','Mental {resilience} separates great athletes from good ones.','정신적 회복 탄력성이 훌륭한 선수와 좋은 선수를 구분해요.','resilience','B2','sports',1,'athlete resilience comeback mental strength sport'),
('w_sports_B2_18','turnover','/ˈtɜːrnoʊvər/','noun','볼 소유권 전환','Losing possession of the ball to the opponent.','Too many {turnover}s cost them the match.','볼 소유권을 너무 많이 잃어 경기를 놓쳤어요.','turnovers','B2','sports',2,'basketball turnover mistake possession lost'),
('w_sports_B2_19','benchmark','/ˈbentʃmɑːrk/','noun','기준, 벤치마크','A standard point of reference for performance.','That world record is the {benchmark} for all sprinters.','그 세계 기록은 모든 단거리 선수의 기준이에요.','benchmark','B2','sports',2,'sports benchmark performance comparison chart data'),
('w_sports_B2_20','overtraining','/ˌoʊvərˈtreɪnɪŋ/','noun','과훈련','Exercising too much, causing declining performance.','Signs of {overtraining} include persistent fatigue.','과훈련의 징후에는 지속적인 피로가 포함돼요.','overtraining','B2','sports',2,'athlete overtraining exhausted injury stressed'),
('w_sports_B2_21','cadence','/ˈkeɪdəns/','noun','케이던스, 보폭 주기','The rate at which steps or strokes are taken in sport.','Cyclists adjust their {cadence} on different terrains.','자전거 선수들은 지형에 따라 케이던스를 조절해요.','cadence','B2','sports',2,'cyclist pedalling cadence rhythm road bike'),
('w_sports_B2_22','scouting','/ˈskaʊtɪŋ/','noun','스카우팅, 선수 탐색','Searching for talented players to recruit.','The club''s {scouting} network spans over 40 countries.','그 클럽의 스카우팅 네트워크는 40개국 이상에 걸쳐 있어요.','scouting','B2','sports',2,'sports scout watching player notebook pitch'),
('w_sports_B2_23','elite','/ɪˈliːt/','adjective','엘리트의, 최고 수준의','Of the highest level of performance.','Only {elite} athletes qualify for the Olympic Games.','엘리트 선수만이 올림픽에 출전할 수 있어요.','elite','B2','sports',1,'elite athletes olympic games competition'),
('w_sports_B2_24','metrics','/ˈmetrɪks/','noun','측정 지표','Standards of measurement used to evaluate performance.','Coaches analyse player {metrics} after every game.','코치들은 모든 경기 후 선수 측정 지표를 분석해요.','metrics','B2','sports',1,'sports metrics data analysis dashboard screen'),
('w_sports_B2_25','intensity','/ɪnˈtensɪti/','noun','강도 (운동 강도)','The level of effort or energy in training.','Training at high {intensity} improves cardiovascular fitness.','높은 강도의 훈련이 심폐 체력을 향상시켜요.','intensity','B2','sports',1,'HIIT training high intensity workout gym'),
('w_sports_B2_26','dehydration','/ˌdiːhaɪˈdreɪʃən/','noun','탈수','An excessive loss of water from the body.','Even mild {dehydration} can impair athletic performance.','가벼운 탈수도 운동 능력을 저하시킬 수 있어요.','dehydration','B2','sports',1,'athlete dehydration dizzy heat sport water'),
('w_sports_B2_27','coordination','/koʊˌɔːrdɪˈneɪʃən/','noun','협응력','The ability to use different parts of the body together.','Good {coordination} is essential for ball sports.','좋은 협응력은 구기 종목에 필수예요.','coordination','B2','sports',1,'athlete coordination drills balance agility'),
('w_sports_B2_28','dominant','/ˈdɒmɪnənt/','adjective','지배적인, 압도적인','Most powerful or influential in a competition.','She has been the {dominant} player in the tour for a decade.','그녀는 10년간 투어에서 압도적인 선수였어요.','dominant','B2','sports',1,'dominant athlete winning easily sport competition'),
('w_sports_B2_29','load','/loʊd/','noun','훈련 부하','The amount of training stress placed on an athlete.','Managing training {load} prevents overuse injuries.','훈련 부하를 관리하면 과사용 부상을 예방할 수 있어요.','load','B2','sports',2,'athlete training load tracker wearable data'),
('w_sports_B2_30','leverage','/ˈlevərɪdʒ/','noun','지렛대 원리, 레버리지','Using body mechanics to gain a mechanical advantage.','Proper technique uses body {leverage} efficiently.','올바른 기술은 신체의 레버리지를 효율적으로 사용해요.','leverage','B2','sports',2,'athlete lifting weights leverage mechanics body'),
('w_sports_B2_31','protocol','/ˈproʊtəkɒl/','noun','프로토콜, 절차','A set of rules about how something should be done.','The medical {protocol} for concussions is very strict.','뇌진탕에 관한 의료 절차는 매우 엄격해요.','protocol','B2','sports',2,'sports medical protocol team doctor procedure'),
('w_sports_B2_32','transition','/trænˈzɪʃən/','noun','전환 (공격·수비)','A change from one state to another in sport.','Quick {transition}s from defence to attack are vital.','수비에서 공격으로의 빠른 전환이 중요해요.','transitions','B2','sports',2,'football attack defence transition counter fast'),
('w_sports_B2_33','simulate','/ˈsɪmjʊleɪt/','verb','시뮬레이션하다','To create conditions similar to a real situation for training.','They {simulated} match conditions during training.','그들은 훈련 중 경기 상황을 시뮬레이션했어요.','simulated','B2','sports',2,'sports simulation training virtual match conditions'),
('w_sports_B2_34','underperform','/ˌʌndəpəˈfɔːrm/','verb','기대 이하의 성과를 내다','To perform less well than expected.','The team {underperformed} despite the talent in the squad.','팀은 스쿼드의 재능에도 불구하고 기대 이하였어요.','underperformed','B2','sports',2,'disappointed team losing sports let down'),
('w_sports_B2_35','output','/ˈaʊtpʊt/','noun','출력, 퍼포먼스 수치','The amount of work or energy produced.','Wattage is the key {output} measure for cyclists.','와트는 자전거 선수의 핵심 출력 측정 단위예요.','output','B2','sports',2,'cyclist power output watt meter data screen');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_C1_01','kinesiology','/ˌkɪniːsiˈɒlədʒi/','noun','운동 과학 (키네시올로지)','The scientific study of human body movement.','She holds a degree in {kinesiology} and works with elite athletes.','그녀는 운동 과학 학위를 갖고 엘리트 선수들과 함께 일해요.','kinesiology','C1','sports',1,'kinesiology lab body movement science sports research'),
('w_sports_C1_02','proprioception','/ˌproʊpriəˈsepʃən/','noun','고유 감각 (프로프리오셉션)','The body''s ability to sense its own position and movement.','Ankle injuries can disrupt an athlete''s {proprioception}.','발목 부상은 선수의 고유 감각을 방해할 수 있어요.','proprioception','C1','sports',1,'balance proprioception training board athlete rehabilitation'),
('w_sports_C1_03','VO2 max','/ˌviː oʊ ˈtuː mæks/','noun','최대 산소 섭취량','The maximum rate of oxygen consumption during exercise.','Improving {VO2 max} is central to endurance training.','최대 산소 섭취량을 높이는 것은 지구력 훈련의 핵심이에요.','VO2 max','C1','sports',1,'VO2 max test mask treadmill lab sports science'),
('w_sports_C1_04','lactate threshold','/ˈlækteɪt ˈθreʃhoʊld/','phrase','젖산 역치','The exercise intensity above which lactate builds up faster than it is removed.','Training at the {lactate threshold} improves race pace significantly.','젖산 역치에서의 훈련은 레이스 페이스를 크게 향상시켜요.','lactate threshold','C1','sports',1,'lactate threshold blood test lab cycling athlete'),
('w_sports_C1_05','periodization','/ˌpɪəriədaɪˈzeɪʃən/','noun','주기화 (고급 계획)','A structured division of training into progressive phases.','Advanced {periodization} involves mesocycles and macrocycles.','고급 주기화에는 메소사이클과 매크로사이클이 포함돼요.','periodization','C1','sports',1,'training plan periodization macrocycle phases sport'),
('w_sports_C1_06','sport psychology','/spɔːrt saɪˈkɒlədʒi/','phrase','스포츠 심리학','The study of mental factors affecting sports performance.','{Sport psychology} techniques help athletes manage pressure.','스포츠 심리학 기술이 선수들이 압박감을 관리하는 데 도움이 돼요.','sport psychology','C1','sports',1,'sport psychologist athlete session mental training'),
('w_sports_C1_07','ethics','/ˈeθɪks/','noun','스포츠 윤리','Moral principles governing behaviour in sport.','The federation published new {ethics} guidelines last year.','연맹이 작년에 새로운 윤리 지침을 발표했어요.','ethics','C1','sports',1,'sports ethics fair play rules committee'),
('w_sports_C1_08','governance','/ˈɡʌvərnəns/','noun','스포츠 거버넌스','The system of rules and institutions controlling a sport.','Concerns about poor {governance} led to major reforms.','열악한 거버넌스에 대한 우려로 대대적인 개혁이 이뤄졌어요.','governance','C1','sports',1,'sports governance board meeting committee reform'),
('w_sports_C1_09','neuromuscular','/ˌnjʊəroʊˈmʌskjʊlər/','adjective','신경근의','Relating to nerves and muscles working together.','The drill targets {neuromuscular} coordination.','그 드릴은 신경근 협응을 목표로 해요.','neuromuscular','C1','sports',2,'neuromuscular training nerve muscle coordination sport'),
('w_sports_C1_10','taper','/ˈteɪpər/','noun','테이퍼 (훈련량 감소)','A gradual reduction in training before a major competition.','Athletes enter a {taper} phase two weeks before the race.','선수들은 경주 2주 전에 테이퍼 단계에 들어가요.','taper','C1','sports',1,'athlete tapering rest lighter training pre-race calm'),
('w_sports_C1_11','overreaching','/ˌoʊvərˈriːtʃɪŋ/','noun','과부하 훈련 (의도적)','A planned short-term increase in training load beyond normal capacity.','Functional {overreaching} is a deliberate strategy before a taper.','기능적 과부하 훈련은 테이퍼 이전의 의도적 전략이에요.','overreaching','C1','sports',2,'training overreaching plan sport science load chart'),
('w_sports_C1_12','isometric','/ˌaɪsəˈmetrɪk/','adjective','등척성의','Relating to muscle contraction without movement.','Plank exercises involve {isometric} muscle contractions.','플랭크 운동에는 등척성 근육 수축이 포함돼요.','isometric','C1','sports',2,'plank isometric exercise core stability hold'),
('w_sports_C1_13','plyometrics','/ˌplaɪəˈmetrɪks/','noun','플라이오메트릭스','Exercises involving rapid stretching and contracting of muscles.','Basketball players use {plyometrics} to build explosive power.','농구 선수들은 폭발적인 힘을 기르기 위해 플라이오메트릭스를 사용해요.','plyometrics','C1','sports',1,'plyometrics box jump training explosive athlete'),
('w_sports_C1_14','hypertrophy','/haɪˈpɜːrtrəfi/','noun','근육 비대','An increase in the size of muscle cells through exercise.','Resistance training induces muscle {hypertrophy}.','저항 훈련은 근육 비대를 유발해요.','hypertrophy','C1','sports',2,'muscle hypertrophy strength training gym results'),
('w_sports_C1_15','anaerobic','/ˌæneɪˈroʊbɪk/','adjective','무산소의','Relating to energy production without oxygen.','Sprinting is an {anaerobic} activity.','단거리 달리기는 무산소 활동이에요.','anaerobic','C1','sports',1,'sprinting anaerobic exercise short burst energy'),
('w_sports_C1_16','sarcopenia','/ˌsɑːrkəˈpiːniə/','noun','근감소증','The loss of muscle mass and strength with ageing.','Strength training combats {sarcopenia} in veteran athletes.','근력 운동은 베테랑 선수들의 근감소증과 싸워요.','sarcopenia','C1','sports',2,'elderly athlete strength training muscle mass aging'),
('w_sports_C1_17','cortisol','/ˈkɔːrtɪzɒl/','noun','코르티솔','A hormone released in response to stress and overtraining.','Chronic overtraining elevates {cortisol} levels, hindering recovery.','만성적인 과훈련은 코르티솔 수준을 높여 회복을 방해해요.','cortisol','C1','sports',2,'hormone cortisol stress sport blood test science'),
('w_sports_C1_18','tendinopathy','/ˌtendɪˈnɒpəθi/','noun','건병증 (힘줄 질환)','A disease of a tendon, often causing chronic pain.','Runners are prone to Achilles {tendinopathy}.','달리기 선수들은 아킬레스 건병증에 걸리기 쉬워요.','tendinopathy','C1','sports',2,'Achilles tendon injury runner physio treatment'),
('w_sports_C1_19','kinesthesia','/ˌkɪnɪsˈθiːziə/','noun','운동 감각','The sense of the position and movement of body parts.','Elite gymnasts have highly refined {kinesthesia}.','엘리트 체조 선수들은 매우 정교한 운동 감각을 갖고 있어요.','kinesthesia','C1','sports',2,'gymnast balance sense movement perception sport'),
('w_sports_C1_20','eccentric','/ɪkˈsentrɪk/','adjective','편심성의 (근육 수축)','Relating to muscle lengthening during contraction.','{Eccentric} exercises are effective for tendon rehabilitation.','편심성 운동은 힘줄 재활에 효과적이에요.','Eccentric','C1','sports',2,'eccentric exercise hamstring physio Nordic curl'),
('w_sports_C1_21','metabolic','/ˌmetəˈbɒlɪk/','adjective','대사적인','Relating to the chemical processes in the body.','High-intensity intervals increase {metabolic} rate.','고강도 인터벌이 대사율을 높여요.','metabolic','C1','sports',2,'metabolic rate exercise sport energy lab test'),
('w_sports_C1_22','fascia','/ˈfæʃiə/','noun','근막','Connective tissue that surrounds muscles and organs.','Myofascial release targets the {fascia} to reduce tension.','근막 이완 요법은 근막의 긴장을 줄이는 것을 목표로 해요.','fascia','C1','sports',2,'fascia muscle connective tissue massage roll'),
('w_sports_C1_23','thermoregulation','/ˌθɜːrmoʊˌreɡjʊˈleɪʃən/','noun','체온 조절','The body''s ability to maintain a stable temperature during exercise.','Effective {thermoregulation} prevents heat exhaustion in athletes.','효과적인 체온 조절은 선수들의 열사병을 예방해요.','thermoregulation','C1','sports',2,'athlete heat sport temperature regulation sweating'),
('w_sports_C1_24','electrolyte','/ɪˈlektrəlaɪt/','noun','전해질','Minerals that maintain fluid balance and muscle function.','Replacing {electrolytes} after heavy sweating is crucial.','땀을 많이 흘린 후 전해질을 보충하는 것이 중요해요.','electrolytes','C1','sports',1,'electrolyte sports drink minerals athlete hydration'),
('w_sports_C1_25','gait','/ɡeɪt/','noun','보행 (걸음걸이)','The way in which a person moves on foot.','Gait analysis helps identify biomechanical faults in runners.','보행 분석은 달리기 선수들의 생체역학적 결함을 찾는 데 도움이 돼요.','Gait','C1','sports',2,'gait analysis running treadmill lab camera motion'),
('w_sports_C1_26','creatine','/ˈkriːətiːn/','noun','크레아틴 (스포츠 영양)','A naturally occurring compound that aids short-burst energy.','Many athletes supplement with {creatine} to boost power output.','많은 선수들이 출력을 높이기 위해 크레아틴을 보충해요.','creatine','C1','sports',2,'creatine supplement sports nutrition powder scoop'),
('w_sports_C1_27','inflammation','/ˌɪnfləˈmeɪʃən/','noun','염증 (스포츠 부상)','The body''s response to injury involving redness and swelling.','Chronic {inflammation} can signal overtraining or injury.','만성 염증은 과훈련이나 부상을 나타낼 수 있어요.','inflammation','C1','sports',2,'sports injury inflammation ice pack swelling treatment'),
('w_sports_C1_28','oxidative','/ˈɒksɪdeɪtɪv/','adjective','산화적인','Relating to the use of oxygen in energy production.','Long-distance events rely on {oxidative} metabolism.','장거리 종목은 산화적 대사에 의존해요.','oxidative','C1','sports',2,'energy metabolism aerobic oxidative sport science chart'),
('w_sports_C1_29','deload','/diːloʊd/','noun','디로드 (훈련량 의도적 감소)','A planned reduction in training volume to aid recovery.','Coaches schedule a {deload} week every four weeks.','코치들은 4주마다 디로드 주를 계획해요.','deload','C1','sports',2,'athlete resting lighter workout recovery week deload'),
('w_sports_C1_30','musculoskeletal','/ˌmʌskjʊloʊˈskelɪtəl/','adjective','근골격의','Relating to the muscles, bones, and connective tissue.','The clinic specialises in {musculoskeletal} injuries.','그 클리닉은 근골격 부상을 전문으로 해요.','musculoskeletal','C1','sports',2,'musculoskeletal injury scan anatomy sports medicine'),
('w_sports_C1_31','catecholamine','/ˌkætɪˈkoʊləmiːn/','noun','카테콜아민 (흥분성 호르몬)','Hormones such as adrenaline released during intense exercise.','High-intensity exercise triggers {catecholamine} release.','고강도 운동은 카테콜아민 분비를 촉진해요.','catecholamine','C1','sports',3,'adrenaline hormone sport excitement high intensity'),
('w_sports_C1_32','ergodynamics','/ˌɜːrɡoʊdaɪˈnæmɪks/','noun','에르고다이나믹스 (운동 효율 역학)','The study of efficient energy use during physical activity.','{Ergodynamics} research helps coaches reduce unnecessary energy expenditure.','에르고다이나믹스 연구는 코치들이 불필요한 에너지 소비를 줄이는 데 도움을 줘요.','Ergodynamics','C1','sports',2,'sports energy efficiency lab research biomechanics'),
('w_sports_C1_33','anthropometry','/ˌænθrəˈpɒmɪtri/','noun','인체 측정학','The measurement of body dimensions for performance analysis.','{Anthropometry} data is used to optimise equipment sizing.','인체 측정 데이터는 장비 크기를 최적화하는 데 사용돼요.','Anthropometry','C1','sports',2,'athlete body measurement tape sports science lab'),
('w_sports_C1_34','decompression','/ˌdiːkəmˈpreʃən/','noun','감압 (회복 기법)','The process of relieving pressure on muscles and joints.','{Decompression} therapy is used for spinal recovery in athletes.','감압 치료는 선수들의 척추 회복에 사용돼요.','Decompression','C1','sports',3,'decompression therapy spine athlete recovery clinic'),
('w_sports_C1_35','psychomotor','/ˌsaɪkoʊˈmoʊtər/','adjective','정신운동의 (입문)','Relating to the interaction between mental activity and physical movement.','Decision-making speed is a key {psychomotor} skill.','의사결정 속도는 핵심적인 정신운동 기술이에요.','psychomotor','C1','sports',2,'psychomotor reaction sport decision making drill');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_C2_01','biomechanical','/ˌbaɪoʊmɪˈkænɪkəl/','adjective','생체역학적','Relating to the mechanics of body movement.','The researchers conducted a {biomechanical} analysis of the throw.','연구원들이 투구 동작의 생체역학적 분석을 수행했어요.','biomechanical','C2','sports',1,'biomechanical analysis lab motion capture athlete study'),
('w_sports_C2_02','neuromotor','/ˌnjʊəroʊˈmoʊtər/','adjective','신경운동의','Relating to the nervous system''s control of movement.','{Neuromotor} training enhances reaction time and coordination.','신경운동 훈련은 반응 시간과 협응력을 향상시켜요.','Neuromotor','C2','sports',2,'neuromotor training reaction agility sport science'),
('w_sports_C2_03','chronobiology','/ˌkrɒnəbaɪˈɒlədʒi/','noun','시간 생물학','The study of biological rhythms and their effect on performance.','{Chronobiology} informs scheduling of peak training times.','시간 생물학은 최적 훈련 시간 설정에 정보를 제공해요.','Chronobiology','C2','sports',2,'chronobiology circadian rhythm sport performance clock'),
('w_sports_C2_04','ergogenic','/ˌɜːrɡəˈdʒenɪk/','adjective','경기력 향상의','Intended to enhance physical performance.','The legality of {ergogenic} aids is a constant debate in sport.','경기력 향상 보조제의 합법성은 스포츠에서 계속되는 논쟁이에요.','ergogenic','C2','sports',1,'ergogenic aid supplement sport legal ethics debate'),
('w_sports_C2_05','myofascial','/ˌmaɪoʊˈfæʃəl/','adjective','근막의','Relating to the connective tissue encasing muscles.','{Myofascial} release techniques are used by sports therapists.','근막 이완 기술은 스포츠 치료사들이 사용해요.','Myofascial','C2','sports',2,'myofascial release foam roller massage therapist muscle'),
('w_sports_C2_06','tensiomyography','/ˌtensiəmaɪˈɒɡrəfi/','noun','텐시오미오그라피 (근육 긴장 측정)','A non-invasive technique to measure muscle contractile properties.','{Tensiomyography} detects muscle imbalances before injuries occur.','텐시오미오그라피는 부상 전에 근육 불균형을 감지해요.','Tensiomyography','C2','sports',2,'tensiomyography muscle measurement sport science probe'),
('w_sports_C2_07','plyometrics','/ˌplaɪəˈmetrɪks/','noun','플라이오메트릭스 (심화)','Exercises using rapid muscle stretch-shortening cycles.','Advanced {plyometrics} programmes are periodised for peak performance.','고급 플라이오메트릭스 프로그램은 최고 경기력을 위해 주기화돼요.','plyometrics','C2','sports',2,'plyometrics advanced depth jump training lab sport'),
('w_sports_C2_08','psychomotor','/ˌsaɪkoʊˈmoʊtər/','adjective','정신운동의 (심화)','Relating to the interaction between mental activity and physical movement.','Elite {psychomotor} drills replicate high-pressure decision-making.','엘리트 정신운동 드릴은 고압적 의사결정을 재현해요.','psychomotor','C2','sports',1,'psychomotor reaction sport decision making speed drill'),
('w_sports_C2_09','glycolysis','/ɡlaɪˈkɒlɪsɪs/','noun','해당 과정','The metabolic breakdown of glucose to produce energy.','Intense sprinting relies heavily on {glycolysis}.','격렬한 스프린팅은 해당 과정에 크게 의존해요.','glycolysis','C2','sports',2,'glycolysis energy metabolism sport science diagram'),
('w_sports_C2_10','somatotype','/ˈsoʊmətəˌtaɪp/','noun','체형 유형 (소마토타입)','A classification of human body type (ectomorph, mesomorph, endomorph).','A mesomorphic {somatotype} is often associated with elite power athletes.','중배엽형 체형은 종종 엘리트 파워 운동선수와 관련이 있어요.','somatotype','C2','sports',2,'body type somatotype mesomorph ectomorph athlete'),
('w_sports_C2_11','mitochondrial','/ˌmaɪtəˈkɒndriəl/','adjective','미토콘드리아의','Relating to the cell structures that produce energy.','Endurance training increases {mitochondrial} density in muscle cells.','지구력 훈련은 근육 세포의 미토콘드리아 밀도를 높여요.','mitochondrial','C2','sports',2,'mitochondria muscle cell energy sport science biology'),
('w_sports_C2_12','electromyography','/ɪˌlektrəʊmaɪˈɒɡrəfi/','noun','근전도 검사 (EMG)','The recording of electrical activity produced by muscles.','{Electromyography} reveals which muscles activate during a squat.','근전도 검사는 스쿼트 중 어떤 근육이 활성화되는지 보여줘요.','Electromyography','C2','sports',2,'EMG electromyography muscle sensors athlete lab'),
('w_sports_C2_13','phosphocreatine','/ˌfɒsfoʊˈkriːətiːn/','noun','포스포크레아틴 (즉각 에너지원)','A high-energy compound used to rapidly regenerate ATP.','{Phosphocreatine} stores are depleted within ten seconds of maximal effort.','포스포크레아틴 저장량은 최대 노력 10초 이내에 고갈돼요.','Phosphocreatine','C2','sports',2,'phosphocreatine ATP energy sprint muscle sport science'),
('w_sports_C2_14','hemodynamics','/ˌhiːmoʊdaɪˈnæmɪks/','noun','혈역학','The dynamics of blood flow through the circulatory system.','Cardiac {hemodynamics} improve significantly with aerobic training.','유산소 훈련으로 심장 혈역학이 크게 개선돼요.','hemodynamics','C2','sports',2,'blood flow heart circulatory aerobic sport science'),
('w_sports_C2_15','mechanoreceptor','/ˌmekənoʊrɪˈseptər/','noun','기계수용체','A sensory receptor that responds to mechanical pressure.','{Mechanoreceptors} in joints help athletes sense body position.','관절의 기계수용체가 선수들이 신체 위치를 감지하는 데 도움을 줘요.','Mechanoreceptors','C2','sports',3,'sensory receptor joint nerve sport science anatomy'),
('w_sports_C2_16','bioenergetics','/ˌbaɪoʊˌenəˈdʒetɪks/','noun','생물에너지학','The study of energy transformations in living organisms.','Understanding {bioenergetics} helps coaches design better training.','생물에너지학을 이해하면 코치들이 더 나은 훈련을 설계할 수 있어요.','bioenergetics','C2','sports',2,'bioenergetics energy lab sport science organism'),
('w_sports_C2_17','catabolism','/kəˈtæbəlɪzəm/','noun','이화 작용','The breakdown of complex molecules in the body for energy.','Overtraining can tip the balance toward {catabolism}.','과훈련은 균형을 이화 작용 쪽으로 기울게 할 수 있어요.','catabolism','C2','sports',2,'catabolism muscle breakdown overtraining science diagram'),
('w_sports_C2_18','anabolism','/əˈnæbəlɪzəm/','noun','동화 작용','The building of complex molecules in the body, enabling growth.','Adequate protein intake supports {anabolism} after training.','충분한 단백질 섭취가 훈련 후 동화 작용을 지원해요.','anabolism','C2','sports',2,'anabolism muscle growth protein sport science'),
('w_sports_C2_19','periodicity','/ˌpɪəriəˈdɪsɪti/','noun','주기성','The quality of recurring in regular cycles in training.','The {periodicity} of elite programmes is carefully calibrated.','엘리트 프로그램의 주기성은 신중하게 조율돼요.','periodicity','C2','sports',2,'training periodicity cycle wave sport program chart'),
('w_sports_C2_20','neurotransmitter','/ˌnjʊəroʊˈtrænsmɪtər/','noun','신경전달물질','A chemical that transmits signals between nerve cells.','Dopamine is a {neurotransmitter} linked to motivation in sport.','도파민은 스포츠에서 동기와 연관된 신경전달물질이에요.','neurotransmitter','C2','sports',3,'dopamine neurotransmitter brain sport motivation science'),
('w_sports_C2_21','proprioceptive','/ˌproʊpriəˈseptɪv/','adjective','고유 감각의','Relating to the perception of body position and movement.','Balance boards develop {proprioceptive} awareness.','균형 보드는 고유 감각 인식을 발달시켜요.','proprioceptive','C2','sports',2,'balance board proprioceptive training athlete rehab'),
('w_sports_C2_22','viscoelastic','/ˌvɪskoʊɪˈlæstɪk/','adjective','점탄성의','Having both viscous and elastic properties, as in tendons.','Tendons are {viscoelastic} structures that store and release energy.','힘줄은 에너지를 저장하고 방출하는 점탄성 구조예요.','viscoelastic','C2','sports',3,'tendon viscoelastic structure energy spring biomechanics'),
('w_sports_C2_23','mechanotransduction','/ˌmekənoʊtrænzˈdʌkʃən/','noun','기계적 신호 전달','The process by which cells convert mechanical stimuli into signals.','Resistance training initiates {mechanotransduction} in muscle fibres.','저항 훈련은 근육 섬유에서 기계적 신호 전달을 시작해요.','mechanotransduction','C2','sports',3,'cell mechanical signal muscle fiber sport science'),
('w_sports_C2_24','allostasis','/ˌæloʊˈsteɪsɪs/','noun','이항상성','Achieving stability through change and adaptation.','{Allostasis} explains how athletes adapt to increasing training loads.','이항상성은 선수들이 증가하는 훈련 부하에 어떻게 적응하는지 설명해요.','Allostasis','C2','sports',3,'allostasis adaptation balance change stress sport'),
('w_sports_C2_25','proteolysis','/ˌproʊtiˈɒlɪsɪs/','noun','단백질 분해','The breakdown of proteins by enzymes.','Prolonged intense exercise accelerates muscle {proteolysis}.','장시간 강도 높은 운동은 근육 단백질 분해를 가속해요.','proteolysis','C2','sports',3,'protein breakdown muscle enzyme sport recovery science'),
('w_sports_C2_26','morphology','/mɔːrˈfɒlədʒi/','noun','형태학 (신체 구조)','The study of the form and structure of organisms.','Skeletal {morphology} influences an athlete''s suitability for a sport.','골격 형태학은 선수의 스포츠 적합성에 영향을 미쳐요.','morphology','C2','sports',3,'skeletal morphology anatomy bone structure sport'),
('w_sports_C2_27','fascicle','/ˈfæsɪkəl/','noun','근섬유다발','A bundle of muscle fibres within a muscle.','Ultrasound imaging can measure {fascicle} length in athletes.','초음파 영상으로 선수의 근섬유다발 길이를 측정할 수 있어요.','fascicle','C2','sports',3,'muscle fascicle fiber bundle ultrasound imaging sport'),
('w_sports_C2_28','ergometer','/ɜːrˈɡɒmɪtər/','noun','에르고미터 (운동 측정 장치)','A device that measures work or power output during exercise.','Rowers train on a rowing {ergometer} indoors.','조정 선수들은 실내 조정 에르고미터로 훈련해요.','ergometer','C2','sports',2,'rowing ergometer indoor training sport machine power'),
('w_sports_C2_29','allometric','/ˌæloʊˈmetrɪk/','adjective','이형성장의','Relating to the differential growth rate of body parts relative to the whole.','Strength-to-weight ratios follow {allometric} scaling principles.','체중 대비 근력 비율은 이형성장 척도 원리를 따라요.','allometric','C2','sports',3,'allometric scaling strength weight ratio sport science'),
('w_sports_C2_30','anaerobiosis','/ˌæneɪˌroʊbaɪˈoʊsɪs/','noun','무산소 생명 현상','The ability to live or function without oxygen.','Short-duration maximal efforts depend on {anaerobiosis}.','단시간 최대 노력은 무산소 생명 현상에 의존해요.','anaerobiosis','C2','sports',3,'anaerobic energy system sport sprint science diagram'),
('w_sports_C2_31','sarcoplasmic','/ˌsɑːrkəˈplæzmɪk/','adjective','근형질의','Relating to the fluid inside muscle cells.','High-rep training induces {sarcoplasmic} hypertrophy.','고반복 훈련은 근형질 비대를 유발해요.','sarcoplasmic','C2','sports',3,'sarcoplasmic hypertrophy muscle cell sport science gym'),
('w_sports_C2_32','polyphasic','/ˌpɒliˈfeɪzɪk/','adjective','다단계성의 (수면·훈련)','Occurring in several phases or cycles.','Some athletes experiment with {polyphasic} sleep schedules.','일부 선수들은 다단계성 수면 일정을 실험해요.','polyphasic','C2','sports',3,'polyphasic sleep schedule sport athlete rest recovery'),
('w_sports_C2_33','tensiometry','/ˌtensiˈɒmɪtri/','noun','장력 측정법','The measurement of tension in muscles or tendons.','{Tensiometry} is used to quantify hamstring tightness.','장력 측정법은 햄스트링 긴장을 정량화하는 데 사용돼요.','Tensiometry','C2','sports',3,'tensiometry hamstring tension measurement sport science'),
('w_sports_C2_34','hemoglobin','/ˈhiːməɡloʊbɪn/','noun','헤모글로빈','The protein in red blood cells that carries oxygen.','Altitude training increases {hemoglobin} concentration in the blood.','고지 훈련은 혈액 내 헤모글로빈 농도를 높여요.','hemoglobin','C2','sports',2,'altitude training hemoglobin blood oxygen sport science'),
('w_sports_C2_35','neuroplasticity','/ˌnjʊəroʊplæˈstɪsɪti/','noun','신경가소성','The brain''s ability to reorganise itself by forming new connections.','Skill acquisition relies on {neuroplasticity} in the motor cortex.','기술 습득은 운동 피질의 신경가소성에 의존해요.','neuroplasticity','C2','sports',2,'brain neuroplasticity learning skill sport motor cortex');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_A1_01','Do you play any sports?','운동 하세요?','Do you play','play는 규칙이 있는 스포츠(축구·야구·농구)에 쓰고, do는 개인 운동(yoga·taekwondo)에 써요.','운동 화제','A1','sports','pattern',NULL,1),
('s_sports_A1_02','I like to swim in summer.','저는 여름에 수영하는 걸 좋아해요.','I like to','좋아하는 운동을 말할 때 "I like to + 동사원형"을 쓰면 간단하고 자연스러워요.','취미 소개','A1','sports','pattern',NULL,2),
('s_sports_A1_03','Can you run fast?','빠르게 달릴 수 있어요?','Can you','Can you + 동사원형?은 능력을 묻는 가장 간단한 방법이에요.','능력 묻기','A1','sports','pattern',NULL,3),
('s_sports_A1_04','What is your favourite sport?','제일 좋아하는 스포츠가 뭐예요?','What is your favourite','favourite 대신 favorite으로도 써요 (미국식). 좋아하는 것을 물을 때 꼭 외워두세요.','선호 묻기','A1','sports','pattern',NULL,4),
('s_sports_A1_05','Let''s play together after school!','방과 후에 같이 운동해요!','Let''s play together','Let''s + 동사원형은 상대방을 함께 하도록 초대할 때 써요.','함께하기 제안','A1','sports','pattern',NULL,5),
('s_sports_A1_06','Our team won the game!','우리 팀이 경기에서 이겼어요!','Our team won','과거형 won은 win의 불규칙 과거예요. 경기 결과를 말할 때 자주 써요.','결과 말하기','A1','sports','pattern',NULL,6),
('s_sports_A1_07','I go to the gym every week.','저는 매주 헬스장에 가요.','I go to the gym','주기를 말할 때 every day / every week / every weekend처럼 뒤에 붙여요.','운동 습관','A1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_A2_01','Did you watch the match last night?','어젯밤 경기 봤어요?','Did you watch','Did you + 동사원형? 패턴으로 과거 행동을 자연스럽게 물어볼 수 있어요.','경기 이야기','A2','sports','pattern',NULL,1),
('s_sports_A2_02','The score was three to one.','점수는 3대 1이었어요.','The score was','영어로 점수를 말할 때 "three to one" 또는 "three-one"으로 읽어요.','경기 결과','A2','sports','pattern',NULL,2),
('s_sports_A2_03','She scored twice in the second half.','그녀는 후반전에 두 번 득점했어요.','scored twice','twice = 두 번. 특정 숫자의 경우 once, twice, three times처럼 써요.','득점 표현','A2','sports','pattern',NULL,3),
('s_sports_A2_04','I can''t believe they lost again.','또 졌다니 믿을 수가 없어요.','I can''t believe','I can''t believe + (that) 절 패턴은 놀람을 표현할 때 자주 써요.','감탄·놀람','A2','sports','pattern',NULL,4),
('s_sports_A2_05','The game ended in a draw.','경기가 무승부로 끝났어요.','ended in a draw','end in a draw는 "무승부로 끝나다"를 뜻하는 고정 표현이에요. ended in a tie도 같은 의미예요.','경기 결과','A2','sports','pattern',NULL,5),
('s_sports_A2_06','Who do you think will win the final?','결승에서 누가 이길 것 같아요?','Who do you think will','Who do you think will + 동사?는 예측을 물을 때 쓰는 자연스러운 표현이에요.','예측 묻기','A2','sports','pattern',NULL,6),
('s_sports_A2_07','He broke the record by two seconds.','그는 기록을 2초 차이로 깼어요.','broke the record','break a record는 "기록을 깨다"는 뜻의 관용 표현이에요. broke는 break의 불규칙 과거형이에요.','기록 표현','A2','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_B1_01','The coach changed the formation at halftime.','코치가 하프타임에 포메이션을 바꿨어요.','changed the formation','at halftime은 "하프타임에"라는 표현으로 경기 분석 시 자주 나와요.','전술 분석','B1','sports','pattern',NULL,1),
('s_sports_B1_02','Our strategy was to press high and win the ball back quickly.','우리 전략은 높게 압박하고 빠르게 공을 되찾는 것이었어요.','Our strategy was to','strategy was to + 동사원형으로 계획을 설명할 수 있어요.','팀 전략','B1','sports','pattern',NULL,2),
('s_sports_B1_03','If we had scored first, the result might have been different.','우리가 먼저 득점했다면, 결과가 달라졌을 수도 있어요.','might have been','If + 과거완료, might have + 과거분사 패턴은 반사실 상황을 말할 때 써요 (3형식 가정법).','가정 표현','B1','sports','pattern',NULL,3),
('s_sports_B1_04','The team focused on maintaining possession throughout the game.','팀은 경기 내내 볼 점유율 유지에 집중했어요.','focused on maintaining','focus on + 동명사 패턴으로 집중한 대상을 표현해요.','전술 묘사','B1','sports','pattern',NULL,4),
('s_sports_B1_05','The referee should have given a penalty in that situation.','심판은 그 상황에서 패널티를 줬어야 했어요.','should have given','should have + 과거분사는 과거에 하지 않은 일에 대한 아쉬움이나 비판을 나타내요.','판정 논평','B1','sports','pattern',NULL,5),
('s_sports_B1_06','I''m not sure why they didn''t substitute the tired striker earlier.','왜 지친 스트라이커를 더 일찍 교체하지 않았는지 모르겠어요.','I''m not sure why','I''m not sure why + 절은 의문과 불만을 부드럽게 표현해요.','전술 의문','B1','sports','pattern',NULL,6),
('s_sports_B1_07','Sportsmanship matters more than winning at all costs.','스포츠맨십은 어떤 대가를 치르더라도 이기는 것보다 더 중요해요.','matters more than','A matters more than B 패턴은 비교 우선순위를 말할 때 써요.','스포츠 가치관','B1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_B2_01','Performance analytics has transformed the way teams approach match preparation.','퍼포먼스 분석이 팀들이 경기 준비에 접근하는 방식을 바꿔놨어요.','has transformed the way','has transformed는 현재완료로 변화의 영향이 지금도 이어짐을 나타내요.','스포츠 분석','B2','sports','pattern',NULL,1),
('s_sports_B2_02','The data suggests that high-pressing tactics significantly increase the chance of winning.','데이터에 따르면 강한 압박 전술이 승리 가능성을 크게 높여요.','The data suggests that','The data suggests that + 절은 분석 결과를 객관적으로 제시하는 학문적 표현이에요.','데이터 인용','B2','sports','pattern',NULL,2),
('s_sports_B2_03','Without proper periodization, athletes risk overtraining and burnout.','적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 처해요.','risk overtraining','risk + 동명사는 "~할 위험에 처하다"는 뜻이에요. risk doing something 형태로 기억하세요.','위험 표현','B2','sports','pattern',NULL,3),
('s_sports_B2_04','Her tactical awareness sets her apart from other players in the league.','그녀의 전술적 감각이 리그의 다른 선수들과 그녀를 구별해줘요.','sets her apart from','set apart from은 "~에서 구별되다, 뛰어나다"는 관용 표현이에요.','비교 강조','B2','sports','pattern',NULL,4),
('s_sports_B2_05','The coaching staff is reviewing biomechanics footage to correct his running form.','코칭 스태프가 달리기 자세를 교정하기 위해 생체역학 영상을 검토 중이에요.','is reviewing','현재진행형(is + -ing)은 현재 진행 중인 지속적 행동을 나타내요.','훈련 분석','B2','sports','pattern',NULL,5),
('s_sports_B2_06','Despite the injury setback, she managed to qualify for the finals.','부상이라는 역경에도 불구하고, 그녀는 결승 진출에 성공했어요.','Despite the','Despite + 명사(구)는 "~에도 불구하고"를 뜻하고, Although + 절과 구별해서 써요.','역경 극복','B2','sports','pattern',NULL,6),
('s_sports_B2_07','It''s worth noting that doping undermines the integrity of the sport.','도핑이 스포츠의 무결성을 훼손한다는 점은 주목할 만해요.','It''s worth noting that','It''s worth noting that은 중요한 사실을 강조할 때 쓰는 격식 표현이에요.','이슈 제기','B2','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_C1_01','Training at the lactate threshold elicits significant aerobic adaptations over time.','젖산 역치에서의 훈련은 시간이 지남에 따라 상당한 유산소 적응을 이끌어내요.','elicits significant','elicit는 "이끌어내다, 유발하다"는 뜻의 격식 동사예요. produce나 cause보다 학술적이에요.','스포츠 과학','C1','sports','pattern',NULL,1),
('s_sports_C1_02','Proprioceptive deficits are commonly observed following ankle sprains in athletes.','고유 감각 결손은 선수들의 발목 염좌 후에 흔히 관찰돼요.','Proprioceptive deficits are commonly observed','수동태(are observed)는 학술 및 의학 텍스트에서 관찰 사실을 객관적으로 서술할 때 자주 써요.','의학적 관찰','C1','sports','pattern',NULL,2),
('s_sports_C1_03','Sport psychology interventions can help athletes reframe failure as a learning opportunity.','스포츠 심리학 개입은 선수들이 실패를 학습 기회로 재해석하도록 도울 수 있어요.','reframe failure as','reframe A as B는 "A를 B로 재해석하다"는 표현으로 인지 변화를 나타내요.','심리적 접근','C1','sports','pattern',NULL,3),
('s_sports_C1_04','Governance failures within sporting bodies have eroded public trust significantly.','스포츠 단체 내의 거버넌스 실패가 대중의 신뢰를 크게 잠식했어요.','have eroded','erode는 "점진적으로 침식하다, 잠식하다"는 뜻이에요. 추상적 개념(신뢰·가치)에 자주 써요.','스포츠 거버넌스','C1','sports','pattern',NULL,4),
('s_sports_C1_05','Without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates.','충분한 회복 없이는 신경근 피로가 쌓이고 경기력이 저하돼요.','accumulates and deteriorates','두 동사를 and로 연결해 결과의 연쇄를 표현해요. deteriorate(저하되다)는 기억해두세요.','과훈련 경고','C1','sports','pattern',NULL,5),
('s_sports_C1_06','Periodization frameworks must account for individual variation in recovery capacity.','주기화 프레임워크는 회복 능력의 개인 차이를 반드시 고려해야 해요.','must account for','must account for는 "반드시 고려해야 한다"는 의무를 나타내는 격식 표현이에요.','훈련 설계','C1','sports','pattern',NULL,6),
('s_sports_C1_07','Ethical considerations in elite sport extend well beyond the arena itself.','엘리트 스포츠의 윤리적 고려 사항은 경기장 자체를 훨씬 넘어서요.','extend well beyond','extend well beyond는 "훨씬 넘어서 확장된다"는 강조 표현이에요. well은 강조 부사예요.','스포츠 윤리','C1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_C2_01','Tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties.','텐시오미오그라피는 골격근 수축 특성을 정량화하는 비침습적 수단을 제공해요.','non-invasive means of quantifying','means of + 동명사는 "~하는 수단"이라는 뜻이에요. 학술 논문에서 흔히 나오는 구조예요.','스포츠 과학 연구','C2','sports','pattern',NULL,1),
('s_sports_C2_02','Chronobiological factors, including circadian rhythm, critically modulate athletic performance across disciplines.','일주기 리듬을 포함한 시간 생물학적 요인이 다양한 종목에서 운동 능력을 결정적으로 조절해요.','critically modulate','modulate는 "조절하다, 변조하다"는 뜻의 고급 동사예요. critically는 "결정적으로"라는 부사예요.','시간 생물학','C2','sports','pattern',NULL,2),
('s_sports_C2_03','The ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry.','포스포크레아틴 보충의 경기력 향상 잠재력은 계속 진행 중인 연구의 주제로 남아 있어요.','remains a subject of ongoing inquiry','remains a subject of ongoing inquiry는 학술적으로 "아직 연구 중인 주제이다"를 표현해요.','학술 논의','C2','sports','pattern',NULL,3),
('s_sports_C2_04','Neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms.','저항 훈련에 대한 신경운동 적응은 중추 및 말초 메커니즘 모두에 의해 매개돼요.','are mediated by','be mediated by는 "~에 의해 매개되다"로 복잡한 인과관계를 학술적으로 설명할 때 써요.','신경과학 설명','C2','sports','pattern',NULL,4),
('s_sports_C2_05','Allometric scaling must be applied when comparing strength outputs across athletes of differing body masses.','서로 다른 체중을 가진 선수들의 근력 출력을 비교할 때 이형성장 척도를 적용해야 해요.','must be applied when comparing','must be applied는 수동 의무 구조예요. when + 동명사(-ing)와 함께 조건을 표현해요.','데이터 비교','C2','sports','pattern',NULL,5),
('s_sports_C2_06','The psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making.','엘리트 경쟁의 정신운동적 요구는 고압적 의사결정을 재현하는 훈련 환경을 필요로 해요.','necessitate a training environment that','necessitate는 "필요로 하다"는 뜻의 고급 타동사예요. demand나 require보다 강한 어조예요.','훈련 설계','C2','sports','pattern',NULL,6),
('s_sports_C2_07','Myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury.','근막 기능 장애가 방치될 경우 보상 운동 패턴을 지속시키고 선수들을 재발성 부상에 취약하게 할 수 있어요.','if left unaddressed','if left unaddressed는 "방치될 경우"라는 뜻의 분사구문 조건절이에요. predispose A to B는 "A를 B에 취약하게 만들다"예요.','부상 예방','C2','sports','pattern',NULL,7);
